+            var status = step < CurrentStep ? "completed"
+                       : step == CurrentStep ? "active"
+                       : "pending";
+            <li class="step-item text-center flex-fill @status"
+                role="listitem"
+                @onclick="() => OnStepClick(step)">
+                <div class="step-circle mx-auto mb-1 rounded-circle d-flex align-items-center justify-content-center
+                            @(status == "active" ? "bg-primary text-white" : status == "completed" ? "bg-success text-white" : "bg-light text-muted border")"
+                     style="width:36px;height:36px;cursor:@(status == "completed" ? "pointer" : "default")">
+                    @if (status == "completed")
+                    {
+                        <span>&#10003;</span>
+                    }
+                    else
+                    {
+                        <span>@(step + 1)</span>
+                    }
+                </div>
+                <small class="@(status == "pending" ? "text-muted" : "")">@StepNames[step]</small>
+            </li>
+        }
+    </ol>
+</nav>
+
+@code {
+    [Parameter, EditorRequired] public int CurrentStep { get; set; }
+    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }
+
+    private static readonly string[] StepNames =
+        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];
+
+    private async Task OnStepClick(int step)
+    {
+        if (step < CurrentStep)
+            await OnStepClicked.InvokeAsync(step);
+    }
+}
