@page "/apply"
@rendermode InteractiveServer
@using sv_87d768d53a5242afad002ada7e5ae1de.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep" OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep Model="_personal"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="_workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="_references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep @bind-CoverLetter="_coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Personal="_personal"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="@_coverLetter"
                        OnEdit="GoToStep"
                        OnBack="PreviousStep"
                        OnSubmit="SubmitAsync" />
            break;
    }
</div>

@code {
    private int _currentStep;
    private PersonalInfoModel _personal = new();
    private List<WorkEntryModel> _workEntries = [new()];
    private List<ReferenceModel> _references = [new(), new()];
    private string _coverLetter = "";

    private void NextStep() => _currentStep = Math.Min(_currentStep + 1, 4);
    private void PreviousStep() => _currentStep = Math.Max(_currentStep - 1, 0);
    private void GoToStep(int step) => _currentStep = step;

    private async Task<int> SubmitAsync()
    {
        var application = new JobApplication(
            _personal.ToRecord(),
            new WorkHistory(_workEntries.Select(e => e.ToRecord()).ToList()),
            _references.Select(r => r.ToRecord()).ToList(),
            _coverLetter
        );
        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

